/**
 * Icon Selector Component
 * Wrapper for IconPicker with better UX — supports Emoji and Font Awesome
 * Author: generated by Amazon Q
 */

'use client';

import React, { useState, useEffect } from 'react';
import { IconConfig, IconDisplay, IconPicker } from './IconPicker';

interface IconSelectorProps {
  value?: IconConfig | null;
  emojiValue?: string;
  onChange: (iconConfig: IconConfig | null, emoji?: string) => void;
  label?: string;
  allowEmoji?: boolean;
  className?: string;
}

export function IconSelector({
  value,
  emojiValue,
  onChange,
  label = 'Icon',
  allowEmoji = true,
  className = '',
}: IconSelectorProps) {
  // Determine initial mode: if iconConfig exists → fontawesome, else emoji
  const [mode, setMode] = useState<'emoji' | 'fontawesome'>(
    value?.name ? 'fontawesome' : 'emoji'
  );
  const [showPicker, setShowPicker] = useState(false);
  const [localEmoji, setLocalEmoji] = useState(emojiValue || '');

  // Sync localEmoji when prop changes
  useEffect(() => {
    setLocalEmoji(emojiValue || '');
  }, [emojiValue]);

  // Sync mode when value prop changes externally
  useEffect(() => {
    if (value?.name) setMode('fontawesome');
  }, [value?.name]);

  const handleModeSwitch = (newMode: 'emoji' | 'fontawesome') => {
    setMode(newMode);
    setShowPicker(false);
    if (newMode === 'emoji') {
      // Clear FA icon, keep emoji
      onChange(null, localEmoji);
    } else {
      // Clear emoji, keep FA icon
      onChange(value || null, '');
    }
  };

  const handleEmojiChange = (val: string) => {
    setLocalEmoji(val);
    onChange(null, val);
  };

  const handleFaSelect = (icon: IconConfig | null) => {
    onChange(icon, '');
    setShowPicker(false);
  };

  const currentIcon = mode === 'fontawesome' ? value : null;
  const currentEmoji = mode === 'emoji' ? localEmoji : '';

  return (
    <div className={`space-y-2 ${className}`}>
      {label && (
        <label className="block text-sm font-medium text-gray-700 dark:text-gray-300">
          {label}
        </label>
      )}

      {/* Mode toggle */}
      {allowEmoji && (
        <div className="flex gap-1 p-1 bg-gray-100 dark:bg-gray-700 rounded-lg">
          <button
            type="button"
            onClick={() => handleModeSwitch('emoji')}
            className={`flex-1 px-3 py-1.5 text-xs rounded-md transition-colors font-medium ${
              mode === 'emoji'
                ? 'bg-white dark:bg-gray-600 text-gray-900 dark:text-white shadow-sm'
                : 'text-gray-500 dark:text-gray-400 hover:text-gray-700 dark:hover:text-gray-200'
            }`}
          >
            😀 Emoji
          </button>
          <button
            type="button"
            onClick={() => handleModeSwitch('fontawesome')}
            className={`flex-1 px-3 py-1.5 text-xs rounded-md transition-colors font-medium ${
              mode === 'fontawesome'
                ? 'bg-white dark:bg-gray-600 text-gray-900 dark:text-white shadow-sm'
                : 'text-gray-500 dark:text-gray-400 hover:text-gray-700 dark:hover:text-gray-200'
            }`}
          >
            <i className="fas fa-icons mr-1" aria-hidden="true" /> Font Awesome
          </button>
        </div>
      )}

      {/* Emoji mode */}
      {mode === 'emoji' && (
        <div className="flex gap-2 items-center">
          <input
            type="text"
            value={localEmoji}
            onChange={(e) => handleEmojiChange(e.target.value)}
            placeholder="e.g. 🚀 ⚡ 📊"
            className="flex-1 px-3 py-2 border border-gray-300 dark:border-gray-600 rounded-md bg-white dark:bg-gray-700 text-gray-900 dark:text-white text-xl text-center"
          />
          {localEmoji && (
            <div className="w-10 h-10 flex items-center justify-center bg-gray-50 dark:bg-gray-700 rounded-lg border border-gray-200 dark:border-gray-600 text-2xl">
              {localEmoji}
            </div>
          )}
        </div>
      )}

      {/* Font Awesome mode */}
      {mode === 'fontawesome' && (
        <div className="space-y-2">
          <button
            type="button"
            onClick={() => setShowPicker(!showPicker)}
            className="w-full px-3 py-2.5 border border-gray-300 dark:border-gray-600 rounded-md bg-white dark:bg-gray-700 hover:bg-gray-50 dark:hover:bg-gray-600 transition-colors text-left"
          >
            {currentIcon ? (
              <div className="flex items-center gap-3">
                {/* Preview icon */}
                <div className="w-8 h-8 flex items-center justify-center bg-gray-100 dark:bg-gray-600 rounded">
                  <IconDisplay icon={currentIcon} />
                </div>
                <div>
                  <div className="text-sm font-medium text-gray-900 dark:text-white">
                    fa-{currentIcon.name}
                  </div>
                  <div className="text-xs text-gray-500 dark:text-gray-400">
                    {currentIcon.type} · {currentIcon.size} · {currentIcon.color}
                  </div>
                </div>
                <span className="ml-auto text-xs text-blue-600 dark:text-blue-400">
                  {showPicker ? '▲ Close' : '▼ Change'}
                </span>
              </div>
            ) : (
              <div className="flex items-center gap-2 text-gray-500 dark:text-gray-400">
                <i className="fas fa-search text-sm" aria-hidden="true" />
                <span className="text-sm">Click to select a Font Awesome icon...</span>
              </div>
            )}
          </button>

          {/* Clear button */}
          {currentIcon && (
            <button
              type="button"
              onClick={() => onChange(null, '')}
              className="text-xs text-red-500 hover:text-red-700 dark:hover:text-red-400"
            >
              ✕ Clear icon
            </button>
          )}

          {/* Picker dropdown */}
          {showPicker && (
            <div className="relative z-50">
              <IconPicker
                value={currentIcon || undefined}
                onChange={handleFaSelect}
                onClose={() => setShowPicker(false)}
                className="shadow-2xl"
              />
            </div>
          )}
        </div>
      )}
    </div>
  );
}
